160	// GetWithArchive resolves a bead ID across the active collection and the
161	// archive partner, with active-wins precedence. This is the lookup the
162	// `ddx bead show` command uses so a closed-and-archived bead remains
163	// addressable by ID.
164	func (s *Store) GetWithArchive(id string) (*Bead, error) {
165		if b, err := s.Get(id); err == nil {
166			return b, nil
167		}
168		if s.Collection != DefaultCollection {
169			return nil, fmt.Errorf("bead: not found: %s", id)
170		}
171		archive := s.archivePartner()
172		b, err := archive.Get(id)
173		if err != nil {
174			return nil, fmt.Errorf("bead: not found: %s", id)
175		}
176		return b, nil
177	}
