1234	// ReadyExecutionBreakdown classifies dependency-ready beads by the reason
1235	// they are NOT execution-eligible: epic containers, retry cooldown,
1236	// execution-eligible=false, or superseded. It's the diagnostic the work loop
1237	// emits when the execution queue is empty but `ddx bead ready` is not.
1238	type ReadyExecutionBreakdown struct {
1239		SkippedEpics       []string
1240		SkippedOnCooldown  []string
1241		SkippedNotEligible []string
1242		SkippedSuperseded  []string
1243		NextRetryAfter     string
