1246	func (s *Store) ReadyExecutionBreakdown() (ReadyExecutionBreakdown, error) {
1247		out := ReadyExecutionBreakdown{}
1248		ready, err := s.Ready()
1249		if err != nil {
1250			return out, err
1251		}
1252		now := time.Now().UTC()
1253		var soonestRetry time.Time
1254		for _, b := range ready {
1255			if retryAfterRaw, ok := b.Extra["execute-loop-retry-after"]; ok {
1256				if retryAfterStr, isStr := retryAfterRaw.(string); isStr && retryAfterStr != "" {
1257					if retryAfter, err := time.Parse(time.RFC3339, retryAfterStr); err == nil && retryAfter.After(now) {
1258						out.SkippedOnCooldown = append(out.SkippedOnCooldown, b.ID)
1259						if soonestRetry.IsZero() || retryAfter.Before(soonestRetry) {
1260							soonestRetry = retryAfter
1261						}
1262						continue
1263					}
1264				}
1265			}
1266			if eligible, ok := b.Extra["execution-eligible"]; ok {
1267				if val, isBool := eligible.(bool); isBool && !val {
1268					out.SkippedNotEligible = append(out.SkippedNotEligible, b.ID)
1269					continue
1270				}
1271			}
1272			if sup, ok := b.Extra["superseded-by"]; ok {
1273				if s, isStr := sup.(string); isStr && s != "" {
1274					out.SkippedSuperseded = append(out.SkippedSuperseded, b.ID)
1275					continue
1276				}
1277			}
1278		}
1279		if !soonestRetry.IsZero() {
1280			out.NextRetryAfter = soonestRetry.Format(time.RFC3339)
1281		}
1282		return out, nil
1283	}
